    public HealthRecordResponse GetPatientRecords(HealthRecordRequest request)
    {
        ValidateRequest(request);

        var audit = CreateAudit("GetPatientRecords", request.RequestingProviderId,
            request.RequestingFacilityId, request.PatientId);

        try
        {
            // Verify consent
            if (!VerifyPatientConsent(request.PatientId, request.RequestingProviderId, request.PurposeOfUse))
            {
                audit.Outcome = "DENIED - No valid consent";
                LogAudit(audit);
                throw new FaultException<HealthcareFault>(
                    new HealthcareFault
                    {
                        ErrorCode = "CONSENT_REQUIRED",
                        ErrorMessage = "Valid patient consent is required for this request.",
                        Timestamp = DateTime.UtcNow
                    },
                    new FaultReason("Patient consent not found or expired."));
            }

            var response = new HealthRecordResponse
            {
                ResponseId = Guid.NewGuid().ToString(),
                RequestId = request.RequestId,
                ResponseTimestamp = DateTime.UtcNow
            };

            // Retrieve patient demographics
            if (PatientStore.ContainsKey(request.PatientId))
            {
                response.PatientDemographics = PatientStore[request.PatientId];
            }
            else
            {
                audit.Outcome = "PATIENT_NOT_FOUND";
                LogAudit(audit);
                response.Success = false;
                response.StatusCode = "PATIENT_NOT_FOUND";
                response.StatusMessage = "No patient found with the specified ID.";
                response.Audit = audit;
                return response;
            }

            // Retrieve medical records
            var records = new List<MedicalRecord>();
            if (RecordStore.ContainsKey(request.PatientId))
            {
                records = RecordStore[request.PatientId];

                // Apply date filters
                if (request.FromDate.HasValue)
                    records = records.FindAll(r => r.EncounterDate >= request.FromDate.Value);
                if (request.ToDate.HasValue)
                    records = records.FindAll(r => r.EncounterDate <= request.ToDate.Value);

                // Apply record type filters
                if (request.RecordTypes != null && request.RecordTypes.Count > 0)
                {
                    records = FilterRecordsByType(records, request.RecordTypes);
                }
            }

            response.MedicalRecords = records;
            response.Success = true;
            response.StatusCode = "SUCCESS";
            response.StatusMessage = $"Retrieved {records.Count} record(s) for patient {request.PatientId}.";

            audit.Outcome = "SUCCESS";
            LogAudit(audit);
            response.Audit = audit;

            return response;
        }
        catch (FaultException)
        {
            throw;
        }
        catch (Exception ex)
        {
            audit.Outcome = "ERROR";
            LogAudit(audit);
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INTERNAL_ERROR",
                    ErrorMessage = "An internal error occurred while processing the request.",
                    ErrorDetail = ex.Message,
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Internal service error."));
        }
    }

    public SubmitRecordResponse SubmitMedicalRecord(SubmitRecordRequest request)
    {
        if (request == null || request.Record == null)
        {
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INVALID_REQUEST",
                    ErrorMessage = "Request and medical record are required.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Invalid request."));
        }

        var audit = CreateAudit("SubmitMedicalRecord", request.SubmittingProviderId,
            request.SubmittingFacilityId, request.PatientDemographics?.PatientId ?? "UNKNOWN");

        try
        {
            string patientId = request.PatientDemographics?.PatientId;

            if (string.IsNullOrEmpty(patientId))
            {
                throw new FaultException<HealthcareFault>(
                    new HealthcareFault
                    {
                        ErrorCode = "MISSING_PATIENT_ID",
                        ErrorMessage = "Patient ID is required.",
                        Timestamp = DateTime.UtcNow
                    },
                    new FaultReason("Missing patient ID."));
            }

            lock (LockObj)
            {
                // Upsert patient demographics
                PatientStore[patientId] = request.PatientDemographics;

                // Assign a record ID
                string recordId = Guid.NewGuid().ToString();
                request.Record.RecordId = recordId;
                request.Record.PatientId = patientId;

                if (!RecordStore.ContainsKey(patientId))
                {
                    RecordStore[patientId] = new List<MedicalRecord>();
                }
                RecordStore[patientId].Add(request.Record);

                audit.Outcome = "SUCCESS";
                LogAudit(audit);

                return new SubmitRecordResponse
                {
                    ResponseId = Guid.NewGuid().ToString(),
                    RequestId = request.RequestId,
                    Success = true,
                    StatusCode = "CREATED",
                    StatusMessage = $"Medical record successfully submitted with ID: {recordId}",
                    AssignedRecordId = recordId,
                    ResponseTimestamp = DateTime.UtcNow,
                    Audit = audit
                };
            }
        }
        catch (FaultException)
        {
            throw;
        }
        catch (Exception ex)
        {
            audit.Outcome = "ERROR";
            LogAudit(audit);
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INTERNAL_ERROR",
                    ErrorMessage = "An error occurred while submitting the record.",
                    ErrorDetail = ex.Message,
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Internal service error."));
        }
    }

    public Patient GetPatientDemographics(string patientId, string requestingProviderId)
    {
        var audit = CreateAudit("GetPatientDemographics", requestingProviderId, null, patientId);

        if (string.IsNullOrEmpty(patientId))
        {
            audit.Outcome = "INVALID_REQUEST";
            LogAudit(audit);
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "MISSING_PATIENT_ID",
                    ErrorMessage = "Patient ID is required.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Missing patient ID."));
        }

        if (PatientStore.ContainsKey(patientId))
        {
            audit.Outcome = "SUCCESS";
            LogAudit(audit);
            return PatientStore[patientId];
        }

        audit.Outcome = "NOT_FOUND";
        LogAudit(audit);
        throw new FaultException<HealthcareFault>(
            new HealthcareFault
            {
                ErrorCode = "PATIENT_NOT_FOUND",
                ErrorMessage = $"No patient found with ID: {patientId}",
                Timestamp = DateTime.UtcNow
            },
            new FaultReason("Patient not found."));
    }

    public List<Medication> GetActiveMedications(string patientId, string requestingProviderId)
    {
        var audit = CreateAudit("GetActiveMedications", requestingProviderId, null, patientId);

        if (!RecordStore.ContainsKey(patientId))
        {
            audit.Outcome = "NO_RECORDS";
            LogAudit(audit);
            return new List<Medication>();
        }

        var activeMeds = new List<Medication>();
        foreach (var record in RecordStore[patientId])
        {
            if (record.Medications != null)
            {
                activeMeds.AddRange(record.Medications.FindAll(m => m.IsActive));
            }
        }

        audit.Outcome = "SUCCESS";
        LogAudit(audit);
        return activeMeds;
    }

    public List<LabResult> GetLabResults(string patientId, DateTime fromDate, DateTime toDate, string requestingProviderId)
    {
        var audit = CreateAudit("GetLabResults", requestingProviderId, null, patientId);

        if (!RecordStore.ContainsKey(patientId))
        {
            audit.Outcome = "NO_RECORDS";
            LogAudit(audit);
            return new List<LabResult>();
        }

        var labResults = new List<LabResult>();
        foreach (var record in RecordStore[patientId])
        {
            if (record.LabResults != null)
            {
                labResults.AddRange(record.LabResults.FindAll(
                    l => l.ResultDate >= fromDate && l.ResultDate <= toDate));
            }
        }

        audit.Outcome = "SUCCESS";
        LogAudit(audit);
        return labResults;
    }

    public bool VerifyPatientConsent(string patientId, string requestingProviderId, string purposeOfUse)
    {
        // In production, this would check a consent management system.
        // For HIPAA, Treatment/Payment/Operations typically have implied consent.
        if (string.IsNullOrEmpty(purposeOfUse))
            return false;

        string purpose = purposeOfUse.ToUpperInvariant();
        if (purpose == "TREATMENT" || purpose == "PAYMENT" || purpose == "OPERATIONS")
        {
            return true;
        }

        // For other purposes, explicit consent record would be checked
        // Simulated: deny if not TPO
        return false;
    }

