    private void ValidateRequest(HealthRecordRequest request)
    {
        if (request == null)
        {
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INVALID_REQUEST",
                    ErrorMessage = "Request cannot be null.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Invalid request."));
        }

        if (string.IsNullOrEmpty(request.PatientId))
        {
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "MISSING_PATIENT_ID",
                    ErrorMessage = "Patient ID is required.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Missing patient ID."));
        }

        if (string.IsNullOrEmpty(request.RequestingProviderId))
        {
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "MISSING_PROVIDER_ID",
                    ErrorMessage = "Requesting provider ID is required.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Missing provider ID."));
        }

        if (string.IsNullOrEmpty(request.PurposeOfUse))
        {
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "MISSING_PURPOSE",
                    ErrorMessage = "Purpose of use is required for HIPAA compliance.",
                    Timestamp = DateTime.UtcNow
                },
                new FaultReason("Missing purpose of use."));
        }
    }

    private List<MedicalRecord> FilterRecordsByType(List<MedicalRecord> records, List<string> types)
    {
        var filtered = new List<MedicalRecord>();
        foreach (var record in records)
        {
            var filteredRecord = new MedicalRecord
            {
                RecordId = record.RecordId,
                PatientId = record.PatientId,
                EncounterDate = record.EncounterDate,
                ProviderId = record.ProviderId,
                ProviderName = record.ProviderName,
                FacilityId = record.FacilityId,
                ClinicalNotes = record.ClinicalNotes
            };

            foreach (var type in types)
            {
                switch (type.ToUpperInvariant())
                {
                    case "DIAGNOSIS":
                        filteredRecord.Diagnoses = record.Diagnoses;
                        break;
                    case "PROCEDURE":
                        filteredRecord.Procedures = record.Procedures;
                        break;
                    case "MEDICATION":
                        filteredRecord.Medications = record.Medications;
                        break;
                    case "LAB":
                        filteredRecord.LabResults = record.LabResults;
                        break;
                    case "VITALS":
                        filteredRecord.Vitals = record.Vitals;
                        break;
                }
            }

            filtered.Add(filteredRecord);
        }
        return filtered;
    }

    private AuditInfo CreateAudit(string action, string userId, string facilityId, string patientId)
    {
        return new AuditInfo
        {
            AuditId = Guid.NewGuid().ToString(),
            Timestamp = DateTime.UtcNow,
            Action = action,
            UserId = userId,
            FacilityId = facilityId,
            PatientId = patientId
        };
    }

    private void LogAudit(AuditInfo audit)
    {
        lock (LockObj)
        {
            AuditLog.Add(audit);
        }
        // In production, persist to a HIPAA-compliant audit log database
        Console.WriteLine($"[AUDIT] {audit.Timestamp:O} | {audit.Action} | User: {audit.UserId} | Patient: {audit.PatientId} | Outcome: {audit.Outcome}");
    }

