// ==================== Custom Certificate Validator ====================

public class HipaaX509CertificateValidator : System.IdentityModel.Selectors.X509CertificateValidator
{
    public override void Validate(X509Certificate2 certificate)
    {
        if (certificate == null)
            throw new ArgumentNullException(nameof(certificate));

        // Verify the certificate is not expired
        if (DateTime.Now > certificate.NotAfter || DateTime.Now < certificate.NotBefore)
        {
            throw new SecurityTokenValidationException("Certificate is expired or not yet valid.");
        }

        // Verify the certificate chain
        using (var chain = new X509Chain())
        {
            chain.ChainPolicy.RevocationMode = X509RevocationMode.Online;
            chain.ChainPolicy.RevocationFlag = X509RevocationFlag.EntireChain;
            chain.ChainPolicy.VerificationFlags = X509VerificationFlags.NoFlag;

            if (!chain.Build(certificate))
            {
                // Log chain status for diagnostics
                foreach (var status in chain.ChainStatus)
                {
                    Console.WriteLine($"[CERT VALIDATION] Chain status: {status.Status} - {status.StatusInformation}");
                }

                // In development/test, you might allow self-signed certs
                // In production, this should throw
                Console.WriteLine("[CERT VALIDATION] WARNING: Certificate chain validation failed. Allowing for development.");
            }
        }

        Console.WriteLine($"[CERT VALIDATION] Certificate validated: {certificate.Subject}");
    }
}

// ==================== Binding Configuration ====================

public static class HealthcareBindingConfiguration
{
    /// <summary>
    /// Creates a WS-Security enabled binding with message-level encryption
    /// suitable for HIPAA compliance.
    /// Uses mutual certificate authentication with AES-256 encryption.
    /// </summary>
    public static CustomBinding CreateHipaaCompliantBinding()
    {
        // Start with WSHttpBinding for WS-Security foundation
        var wsBinding = new WSHttpBinding(SecurityMode.Message);
        wsBinding.Security.Message.ClientCredentialType = MessageCredentialType.Certificate;
        wsBinding.Security.Message.EstablishSecurityContext = true;
        wsBinding.Security.Message.NegotiateServiceCredential = false;

        // Create custom binding for fine-grained security control
        var customBinding = new CustomBinding(wsBinding);

        // Configure the security binding element
        var securityElement = customBinding.Elements.Find<SecurityBindingElement>();
        if (securityElement != null)
        {
            // Set security algorithm suite to AES-256 for HIPAA compliance
            securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

            // Enable secure conversation for session-based security
            securityElement.IncludeTimestamp = true;
            securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;
            securityElement.MessageSecurityVersion =
                MessageSecurityVersion.WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10;

            // Configure key entropy mode
            securityElement.KeyEntropyMode = SecurityKeyEntropyMode.CombinedEntropy;

            // Set token parameters for encryption
            securityElement.SetKeyDerivation(true);

            // Message protection order: Sign then Encrypt
            if (securityElement is SymmetricSecurityBindingElement symmetricElement)
            {
                symmetricElement.MessageProtectionOrder = MessageProtectionOrder.SignBeforeEncryptAndEncryptSignature;
                symmetricElement.RequireSignatureConfirmation = true;
            }
            else if (securityElement is AsymmetricSecurityBindingElement asymmetricElement)
            {
                asymmetricElement.MessageProtectionOrder = MessageProtectionOrder.SignBeforeEncryptAndEncryptSignature;
                asymmetricElement.RequireSignatureConfirmation = true;
            }
        }

        // Configure transport for reliability
        var httpTransport = customBinding.Elements.Find<HttpTransportBindingElement>();
        if (httpTransport != null)
        {
            httpTransport.MaxReceivedMessageSize = 10 * 1024 * 1024; // 10 MB
            httpTransport.MaxBufferSize = 10 * 1024 * 1024;
        }

        // Configure text message encoding
        var textEncoding = customBinding.Elements.Find<TextMessageEncodingBindingElement>();
        if (textEncoding != null)
        {
            textEncoding.MessageVersion = MessageVersion.Soap12WSAddressing10;
            textEncoding.MaxReadPoolSize = 64;
            textEncoding.MaxWritePoolSize = 16;
            textEncoding.ReaderQuotas.MaxDepth = 128;
            textEncoding.ReaderQuotas.MaxStringContentLength = 8192 * 1024;
            textEncoding.ReaderQuotas.MaxArrayLength = 16384 * 1024;
        }

        return customBinding;
    }

    /// <summary>
    /// Creates a binding with transport + message security (belt and suspenders)
    /// for maximum HIPAA protection.
    /// </summary>
    public static CustomBinding CreateDualLayerSecurityBinding()
    {
        var binding = new WSHttpBinding(SecurityMode.TransportWithMessageCredential);
        binding.Security.Message.ClientCredentialType = MessageCredentialType.Certificate;
        binding.Security.Message.EstablishSecurityContext = true;

        var customBinding = new CustomBinding(binding);

        var securityElement = customBinding.Elements.Find<SecurityBindingElement>();
        if (securityElement != null)
        {
            securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;
            securityElement.IncludeTimestamp = true;
        }

        var httpsTransport = customBinding.Elements.Find<HttpsTransportBindingElement>();
        if (httpsTransport != null)
        {
            httpsTransport.RequireClientCertificate = true;
            httpsTransport.MaxReceivedMessageSize = 10 * 1024 * 1024;
        }

        return customBinding;
    }
}

// ==================== Service Host Configuration ====================

public class HealthcareServiceHostFactory
{
    /// <summary>
    /// Creates and configures a WCF ServiceHost with HIPAA-compliant security.
    /// </summary>
    public static ServiceHost CreateServiceHost(string baseAddress, string certSubjectName)
    {
        var host = new ServiceHost(typeof(HealthcareRecordService), new Uri(baseAddress));

        // Get the HIPAA-compliant binding
        var binding = HealthcareBindingConfiguration.CreateHipaaCompliantBinding();

        // Add the service endpoint
        var endpoint = host.AddServiceEndpoint(
            typeof(IHealthcareRecordService),
            binding,
            "HealthRecords");

        // Configure service credentials
        ConfigureServiceCredentials(host, certSubjectName);

        // Configure service behavior
        ConfigureServiceBehavior(host);

        // Add metadata endpoint (for development; disable in production or secure it)
        ConfigureMetadata(host, baseAddress);

        return host;
    }

    private static void ConfigureServiceCredentials(ServiceHost host, string certSubjectName)
    {
        // Service certificate for signing and encryption
        host.Credentials.ServiceCertificate.SetCertificate(
            StoreLocation.LocalMachine,
            StoreName.My,
            X509FindType.FindBySubjectName,
            certSubjectName);

        // Client certificate authentication
        host.Credentials.ClientCertificate.Authentication.CertificateValidationMode =
            X509CertificateValidationMode.Custom;
        host.Credentials.ClientCertificate.Authentication.CustomCertificateValidator =
            new HipaaX509CertificateValidator();

        // Revocation checking
        host.Credentials.ClientCertificate.Authentication.RevocationMode = X509RevocationMode.Online;

        // Map client certificates to Windows accounts (optional for additional authorization)
        host.Credentials.ClientCertificate.Authentication.MapClientCertificateToWindowsAccount = false;

        // Configure issued token authentication (for federated scenarios)
        host.Credentials.IssuedTokenAuthentication.AllowUntrustedRsaIssuers = false;
    }

    private static void ConfigureServiceBehavior(ServiceHost host)
    {
        var serviceBehavior = host.Description.Behaviors.Find<ServiceBehaviorAttribute>();
        if (serviceBehavior == null)
        {
            serviceBehavior = new ServiceBehaviorAttribute();
            host.Description.Behaviors.Add(serviceBehavior);
        }

        // Do not include exception details in production
        serviceBehavior.IncludeExceptionDetailInFaults = false;

        // Configure throttling for production
        var throttle = host.Description.Behaviors.Find<ServiceThrottlingBehavior>();
        if (throttle == null)
        {
            throttle = new ServiceThrottlingBehavior();
            host.Description.Behaviors.Add(throttle);
        }
        throttle.MaxConcurrentCalls = 100;
        throttle.MaxConcurrentInstances = 100;
        throttle.MaxConcurrentSessions = 100;

        // Configure service debug behavior
        var debugBehavior = host.Description.Behaviors.Find<ServiceDebugBehavior>();
        if (debugBehavior == null)
        {
            debugBehavior = new ServiceDebugBehavior();
            host.Description.Behaviors.Add(debugBehavior);
        }
        debugBehavior.IncludeExceptionDetailInFaults = false;
    }

    private static void ConfigureMetadata(ServiceHost host, string baseAddress)
    {
        var metadataBehavior = host.Description.Behaviors.Find<ServiceMetadataBehavior>();
        if (metadataBehavior == null)
        {
            metadataBehavior = new ServiceMetadataBehavior();
            host.Description.Behaviors.Add(metadataBehavior);
        }

        // In production, use HTTPS and restrict access
        metadataBehavior.HttpGetEnabled = true;
        metadataBehavior.HttpGetUrl = new Uri(baseAddress + "/mex");

        host.AddServiceEndpoint(
            typeof(IMetadataExchange),
            MetadataExchangeBindings.CreateMexHttpBinding(),
            "mex");
    }
}

