public static class HealthcareClientFactory
{
    /// <summary>
    /// Creates a configured client for the Healthcare Record Service with mutual certificate authentication.
    /// </summary>
    public static HealthcareServiceClient CreateClient(
        string serviceUrl,
        string clientCertSubjectName,
        string serviceCertSubjectName)
    {
        var binding = HealthcareBindingConfiguration.CreateHipaaCompliantBinding();

        var identity = new X509CertificateEndpointIdentity(
            FindCertificate(StoreLocation.LocalMachine, StoreName.TrustedPeople,
                X509FindType.FindBySubjectName, serviceCertSubjectName));

        var address = new EndpointAddress(new Uri(serviceUrl), identity);

        var client = new HealthcareServiceClient(binding, address);

        // Set client certificate
        client.ClientCredentials.ClientCertificate.SetCertificate(
            StoreLocation.CurrentUser,
            StoreName.My,
            X509FindType.FindBySubjectName,
            clientCertSubjectName);

        // Configure service certificate for message encryption
        client.ClientCredentials.ServiceCertificate.SetDefaultCertificate(
            StoreLocation.LocalMachine,
            StoreName.TrustedPeople,
            X509FindType.FindBySubjectName,
            serviceCertSubjectName);

        // Certificate validation
        client.ClientCredentials.ServiceCertificate.Authentication.CertificateValidationMode =
            X509CertificateValidationMode.ChainTrust;
        client.ClientCredentials.ServiceCertificate.Authentication.RevocationMode =
            X509RevocationMode.Online;

        return client;
    }

    private static X509Certificate2 FindCertificate(
        StoreLocation location, StoreName storeName,
        X509FindType findType, string findValue)
    {
        var store = new X509Store(storeName, location);
        try
        {
            store.Open(OpenFlags.ReadOnly);
            var certs = store.Certificates.Find(findType, findValue, false);
            if (certs.Count == 0)
                throw new InvalidOperationException($"Certificate not found: {findValue}");
            return certs[0];
        }
        finally
        {
            store.Close();
        }
    }
}

